{
  "name": "KakaoAuto Controller",
  "description": "A modern, user-friendly dashboard to configure and control the KakaoTalk Python automation script. Features include visual message editing, recipient management, and real-time log monitoring."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppMode {
  DASHBOARD = 'DASHBOARD',
  MESSAGES = 'MESSAGES',
  RECIPIENTS = 'RECIPIENTS',
  SETTINGS = 'SETTINGS',
  LOGS = 'LOGS'
}

export enum AutomationMode {
  LIST = 'LIST',
  BATCH = 'BATCH'
}

export interface AutomationConfig {
  windowTitle: string;
  kakaoPath: string;
  repeatCount: number;
  sendInterval: number;
  automationMode: AutomationMode;
}

export interface LogEntry {
  id: string;
  timestamp: string;
  level: 'INFO' | 'WARN' | 'ERROR';
  message: string;
}

export interface Recipient {
  id: string;
  name: string;
}

import React from 'react';
import { LayoutDashboard, MessageSquare, Users, Settings, Terminal, Zap } from 'lucide-react';
import { AppMode } from '../types';

interface SidebarProps {
  currentMode: AppMode;
  setMode: (mode: AppMode) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentMode, setMode }) => {
  const navItems = [
    { mode: AppMode.DASHBOARD, icon: LayoutDashboard, label: 'Dashboard' },
    { mode: AppMode.MESSAGES, icon: MessageSquare, label: 'Message Editor' },
    { mode: AppMode.RECIPIENTS, icon: Users, label: 'Recipients' },
    { mode: AppMode.SETTINGS, icon: Settings, label: 'Configuration' },
    { mode: AppMode.LOGS, icon: Terminal, label: 'Live Logs' },
  ];

  return (
    <div className="w-64 bg-white h-screen border-r border-gray-200 flex flex-col fixed left-0 top-0 z-10">
      <div className="p-6 flex items-center space-x-3 border-b border-gray-100">
        <div className="bg-kakao-yellow p-2 rounded-lg">
          <Zap className="text-kakao-brown w-6 h-6" />
        </div>
        <div>
          <h1 className="font-bold text-lg text-gray-800">KakaoAuto</h1>
          <p className="text-xs text-gray-500">Automation Control</p>
        </div>
      </div>

      <nav className="flex-1 p-4 space-y-2">
        {navItems.map((item) => (
          <button
            key={item.mode}
            onClick={() => setMode(item.mode)}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-xl transition-all duration-200 ${
              currentMode === item.mode
                ? 'bg-kakao-yellow text-kakao-brown font-semibold shadow-sm'
                : 'text-gray-500 hover:bg-gray-50 hover:text-gray-900'
            }`}
          >
            <item.icon className={`w-5 h-5 ${currentMode === item.mode ? 'text-kakao-brown' : 'text-gray-400'}`} />
            <span>{item.label}</span>
          </button>
        ))}
      </nav>

      <div className="p-4 border-t border-gray-100">
        <div className="bg-gray-50 rounded-xl p-4">
          <div className="flex items-center space-x-2 mb-2">
            <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
            <span className="text-xs font-medium text-gray-600">System Ready</span>
          </div>
          <p className="text-xs text-gray-400">v2.0.26 (Beta)</p>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React from 'react';
import { Play, Square, Clock, Users, MessageCircle, AlertTriangle } from 'lucide-react';
import { AutomationConfig, AutomationMode, LogEntry } from '../types';

interface DashboardProps {
  config: AutomationConfig;
  isRunning: boolean;
  onToggleRun: () => void;
  recentLogs: LogEntry[];
  totalRecipients: number;
}

const Dashboard: React.FC<DashboardProps> = ({ config, isRunning, onToggleRun, recentLogs, totalRecipients }) => {
  return (
    <div className="p-8 space-y-8">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Automation Dashboard</h2>
          <p className="text-gray-500">Overview of your current session and status.</p>
        </div>
        <button
          onClick={onToggleRun}
          className={`flex items-center space-x-2 px-6 py-3 rounded-full font-bold shadow-lg transition-transform active:scale-95 ${
            isRunning
              ? 'bg-red-500 text-white hover:bg-red-600'
              : 'bg-kakao-yellow text-kakao-brown hover:bg-yellow-400'
          }`}
        >
          {isRunning ? <Square className="w-5 h-5 fill-current" /> : <Play className="w-5 h-5 fill-current" />}
          <span>{isRunning ? 'Stop Automation' : 'Start Automation'}</span>
        </button>
      </div>

      {/* Status Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-start">
            <div className="p-3 bg-blue-50 rounded-xl">
              <Clock className="w-6 h-6 text-blue-600" />
            </div>
            <span className={`px-3 py-1 rounded-full text-xs font-medium ${isRunning ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-600'}`}>
              {isRunning ? 'Running' : 'Idle'}
            </span>
          </div>
          <div className="mt-4">
            <h3 className="text-3xl font-bold text-gray-900">{config.sendInterval}s</h3>
            <p className="text-sm text-gray-500">Interval Delay</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-start">
            <div className="p-3 bg-purple-50 rounded-xl">
              <Users className="w-6 h-6 text-purple-600" />
            </div>
            <span className="px-3 py-1 rounded-full text-xs font-medium bg-gray-100 text-gray-600">
              {config.automationMode}
            </span>
          </div>
          <div className="mt-4">
            <h3 className="text-3xl font-bold text-gray-900">
              {config.automationMode === AutomationMode.BATCH ? '∞' : totalRecipients}
            </h3>
            <p className="text-sm text-gray-500">
              {config.automationMode === AutomationMode.BATCH ? 'Sequential Processing' : 'Targets Loaded'}
            </p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-start">
            <div className="p-3 bg-orange-50 rounded-xl">
              <MessageCircle className="w-6 h-6 text-orange-600" />
            </div>
          </div>
          <div className="mt-4">
            <h3 className="text-3xl font-bold text-gray-900">{config.repeatCount}</h3>
            <p className="text-sm text-gray-500">Cycle Repeats</p>
          </div>
        </div>
      </div>

      {/* Warnings / Instructions */}
      {config.automationMode === AutomationMode.BATCH && (
        <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 flex items-start space-x-3">
          <AlertTriangle className="w-6 h-6 text-amber-600 flex-shrink-0 mt-0.5" />
          <div>
            <h4 className="font-semibold text-amber-800">Batch Mode Active</h4>
            <p className="text-sm text-amber-700 mt-1">
              Ensure you have manually selected the <strong>first chat</strong> in your KakaoTalk list before starting. The automation will press 'Enter', send, 'Alt+F4', and 'Down Arrow' recursively.
            </p>
          </div>
        </div>
