          <span className="text-xs text-gray-500">Connected to local instance</span>
        </div>
        <div className="space-y-2 max-h-48 overflow-y-auto">
          {recentLogs.length === 0 ? (
            <div className="text-gray-600 italic">No activity recorded yet...</div>
          ) : (
            recentLogs.slice(-5).map((log) => (
              <div key={log.id} className="flex space-x-3">
                <span className="text-gray-500">[{log.timestamp}]</span>
                <span className={
                  log.level === 'ERROR' ? 'text-red-400' :
                  log.level === 'WARN' ? 'text-yellow-400' : 'text-green-400'
                }>{log.level}</span>
                <span className="text-gray-300">{log.message}</span>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Plus, Trash2, Search, FileText } from 'lucide-react';
import { Recipient } from '../types';

interface RecipientListProps {
  recipients: Recipient[];
  setRecipients: (list: Recipient[]) => void;
}

const RecipientList: React.FC<RecipientListProps> = ({ recipients, setRecipients }) => {
  const [newInput, setNewInput] = useState('');

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newInput.trim()) return;

    const newItem: Recipient = {
        id: Date.now().toString(),
        name: newInput.trim()
    };

    setRecipients([...recipients, newItem]);
    setNewInput('');
  };

  const handleDelete = (id: string) => {
    setRecipients(recipients.filter(r => r.id !== id));
  };

  return (
    <div className="p-8 h-full flex flex-col">
       <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Recipient Management</h2>
          <p className="text-gray-500">Manage the target list for 'List Mode' execution.</p>
        </div>
        <div className="bg-blue-50 text-blue-700 px-4 py-2 rounded-lg text-sm font-medium flex items-center space-x-2">
            <FileText className="w-4 h-4" />
            <span>recipients.txt</span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 flex-1">
        {/* Left Column: Add New */}
        <div className="lg:col-span-1 space-y-4">
            <form onSubmit={handleAdd} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200">
                <h3 className="font-semibold text-gray-800 mb-4">Add Recipient</h3>
                <div className="space-y-3">
                    <input
                        type="text"
                        value={newInput}
                        onChange={(e) => setNewInput(e.target.value)}
                        placeholder="Enter Exact KakaoTalk Name"
                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-kakao-yellow focus:border-transparent transition-all"
                    />
                    <button 
                        type="submit"
                        className="w-full bg-gray-900 text-white font-medium py-3 rounded-xl hover:bg-gray-800 transition-colors flex justify-center items-center space-x-2"
                    >
                        <Plus className="w-4 h-4" />
                        <span>Add to List</span>
                    </button>
                </div>
            </form>

            <div className="bg-gray-50 rounded-2xl p-6 border border-gray-100">
                <h4 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-3">Note</h4>
                <p className="text-sm text-gray-600 leading-relaxed">
                    Ensure names match exactly with your KakaoTalk friend list names. The automation uses the search bar `Ctrl+F` to find these contacts.
                </p>
            </div>
        </div>

        {/* Right Column: List */}
        <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-gray-200 flex flex-col overflow-hidden">
            <div className="p-4 border-b border-gray-100 flex items-center space-x-3 bg-gray-50/50">
                <Search className="w-5 h-5 text-gray-400" />
                <input 
                    type="text" 
                    placeholder="Filter list..." 
                    className="bg-transparent border-none focus:outline-none flex-1 text-sm"
                />
                <span className="text-xs font-semibold text-gray-400 bg-gray-100 px-2 py-1 rounded">
                    {recipients.length} Targets
                </span>
            </div>

            <div className="flex-1 overflow-y-auto p-2 space-y-1">
                {recipients.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-gray-400 opacity-50">
                        <Users className="w-12 h-12 mb-2" />
                        <span>List is empty</span>
                    </div>
                ) : (
                    recipients.map((recipient) => (
                        <div key={recipient.id} className="group flex items-center justify-between p-3 hover:bg-gray-50 rounded-xl transition-colors border border-transparent hover:border-gray-100">
                            <div className="flex items-center space-x-3">
                                <div className="w-8 h-8 rounded-full bg-gradient-to-br from-gray-100 to-gray-200 flex items-center justify-center text-xs font-bold text-gray-500">
                                    {recipient.name.substring(0,1)}
                                </div>
                                <span className="text-gray-700 font-medium">{recipient.name}</span>
                            </div>
                            <button 
                                onClick={() => handleDelete(recipient.id)}
                                className="text-gray-300 hover:text-red-500 p-2 opacity-0 group-hover:opacity-100 transition-all"
                            >
                                <Trash2 className="w-4 h-4" />
                            </button>
                        </div>
                    ))
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

export default RecipientList;

