export default LogTerminal;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import MessageEditor from './components/MessageEditor';
import RecipientList from './components/RecipientList';
import ConfigForm from './components/ConfigForm';
import LogTerminal from './components/LogTerminal';
import { AppMode, AutomationConfig, AutomationMode, LogEntry, Recipient } from './types';

const App: React.FC = () => {
  const [currentMode, setMode] = useState<AppMode>(AppMode.DASHBOARD);
  const [isRunning, setIsRunning] = useState(false);

  // State for automation configuration
  const [config, setConfig] = useState<AutomationConfig>({
    windowTitle: '카카오톡',
    kakaoPath: 'C:\\Program Files (x86)\\Kakao\\KakaoTalk\\KakaoTalk.exe',
    repeatCount: 1,
    sendInterval: 3,
    automationMode: AutomationMode.LIST,
  });

  // State for data
  const [message, setMessage] = useState("안녕하세요,\n자동 메시지입니다.\n(smile)");
  const [recipients, setRecipients] = useState<Recipient[]>([
    { id: '1', name: '최웅비' },
    { id: '2', name: '홍길동' },
  ]);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Simulate logs when running
  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isRunning) {
        interval = setInterval(() => {
            const newLog: LogEntry = {
                id: Date.now().toString(),
                timestamp: new Date().toLocaleTimeString([], { hour12: false }),
                level: Math.random() > 0.9 ? 'WARN' : 'INFO',
                message: config.automationMode === AutomationMode.BATCH 
                    ? `Processing batch item... Window focus check OK.`
                    : `Sending message to user ID: ${Math.floor(Math.random() * 1000)}... Success.`
            };
            setLogs(prev => [...prev, newLog]);
        }, 2000);
    }
    return () => clearInterval(interval);
  }, [isRunning, config.automationMode]);

  const toggleRun = () => {
    setIsRunning(!isRunning);
    if (!isRunning) {
        setLogs(prev => [...prev, {
            id: Date.now().toString(),
            timestamp: new Date().toLocaleTimeString([], { hour12: false }),
            level: 'INFO',
            message: `Starting automation service in ${config.automationMode} mode...`
        }]);
    } else {
        setLogs(prev => [...prev, {
            id: Date.now().toString(),
            timestamp: new Date().toLocaleTimeString([], { hour12: false }),
            level: 'INFO',
            message: 'Automation stopped by user.'
        }]);
    }
  };

  const renderContent = () => {
    switch (currentMode) {
      case AppMode.DASHBOARD:
        return <Dashboard 
            config={config} 
            isRunning={isRunning} 
            onToggleRun={toggleRun} 
            recentLogs={logs}
            totalRecipients={recipients.length}
        />;
      case AppMode.MESSAGES:
        return <MessageEditor message={message} setMessage={setMessage} />;
      case AppMode.RECIPIENTS:
        return <RecipientList recipients={recipients} setRecipients={setRecipients} />;
      case AppMode.SETTINGS:
        return <ConfigForm config={config} setConfig={setConfig} />;
      case AppMode.LOGS:
        return <LogTerminal logs={logs} onClear={() => setLogs([])} />;
      default:
        return <Dashboard 
            config={config} 
            isRunning={isRunning} 
            onToggleRun={toggleRun} 
            recentLogs={logs}
            totalRecipients={recipients.length}
        />;
    }
  };

  return (
    <div className="flex min-h-screen bg-[#F3F4F6]">
      <Sidebar currentMode={currentMode} setMode={setMode} />
      <div className="flex-1 ml-64">
        {renderContent()}
      </div>
    </div>
  );
};

