                        {config.automationMode === AutomationMode.BATCH && <div className="w-3 h-3 rounded-full bg-kakao-yellow"></div>}
                    </div>
                    <p className="text-sm text-gray-500">Iterates through chat list sequentially using arrow keys. Requires manual start focus.</p>
                </label>
            </div>
        </div>

        {/* Timings */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">Execution Timings</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Send Interval (Seconds)</label>
                    <input 
                        type="number" 
                        value={config.sendInterval}
                        onChange={(e) => handleChange('sendInterval', parseInt(e.target.value))}
                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-kakao-yellow"
                    />
                    <p className="mt-1 text-xs text-gray-400">Delay between finishing one user and starting the next.</p>
                </div>
                 <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Repeat Count</label>
                    <input 
                        type="number" 
                        value={config.repeatCount}
                        onChange={(e) => handleChange('repeatCount', parseInt(e.target.value))}
                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-kakao-yellow"
                    />
                    <p className="mt-1 text-xs text-gray-400">Number of full loops to execute (usually 1).</p>
                </div>
            </div>
        </div>

        {/* Advanced Paths */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">Application Paths</h3>
            <div className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">KakaoTalk Executable Path</label>
                    <input 
                        type="text" 
                        value={config.kakaoPath}
                        onChange={(e) => handleChange('kakaoPath', e.target.value)}
                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-kakao-yellow font-mono text-sm"
                    />
                </div>
                 <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Window Title</label>
                    <input 
                        type="text" 
                        value={config.windowTitle}
                        onChange={(e) => handleChange('windowTitle', e.target.value)}
                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-kakao-yellow"
                    />
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

