import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import MessageEditor from './components/MessageEditor';
import RecipientList from './components/RecipientList';
import ConfigForm from './components/ConfigForm';
import LogTerminal from './components/LogTerminal';
import { AppMode, AutomationConfig, AutomationMode, LogEntry, Recipient, ConnectionStatus } from './types';

// Assuming the Python FastAPI server runs on port 8000
const API_URL = 'http://localhost:8000/api';

const App: React.FC = () => {
  const [currentMode, setMode] = useState<AppMode>(AppMode.DASHBOARD);
  const [connectionStatus, setConnectionStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [isRunning, setIsRunning] = useState(false);

  // State for automation configuration
  const [config, setConfig] = useState<AutomationConfig>({
    windowTitle: '카카오톡',
    kakaoPath: 'C:\\Program Files (x86)\\Kakao\\KakaoTalk\\KakaoTalk.exe',
    repeatCount: 1,
    sendInterval: 3,
    automationMode: AutomationMode.LIST,
  });

  const [message, setMessage] = useState("안녕하세요,\n자동 메시지입니다.\n(smile)");
  const [recipients, setRecipients] = useState<Recipient[]>([
    { id: '1', name: '최웅비' },
  ]);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  // --- API Integrations ---

  const checkStatus = async () => {
    try {
        const response = await fetch(`${API_URL}/status`);
        if (response.ok) {
            const data = await response.json();
            setConnectionStatus(ConnectionStatus.CONNECTED);
            setIsRunning(data.isRunning);
            if (data.logs && data.logs.length > 0) {
                 // In a real app, merge logs smartly. For now, we replace.
                 setLogs(data.logs); 
            }
        } else {
            setConnectionStatus(ConnectionStatus.DISCONNECTED);
        }
    } catch (e) {
        setConnectionStatus(ConnectionStatus.DISCONNECTED);
    }
  };

  // Poll status every 2 seconds
  useEffect(() => {
    checkStatus();
    const interval = setInterval(checkStatus, 2000);
    return () => clearInterval(interval);
  }, []);

  const handleToggleRun = async () => {
    if (connectionStatus !== ConnectionStatus.CONNECTED) {
        alert("Backend not connected. Ensure server.py is running.");
        return;
    }

    const endpoint = isRunning ? 'stop' : 'start';
    try {
        await fetch(`${API_URL}/${endpoint}`, { method: 'POST' });
        // Immediate status check
        checkStatus();
    } catch (e) {
        console.error("Failed to toggle run state", e);
    }
  };

  const handleSaveConfig = async (newConfig: AutomationConfig) => {
    if (connectionStatus === ConnectionStatus.CONNECTED) {
        try {
            await fetch(`${API_URL}/config`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(newConfig)
            });
        } catch (e) { console.error(e); }
    } else {
        console.log("Offline mode: Config updated locally");
    }
    setConfig(newConfig);
  };

  const handleSaveMessage = async (msg: string) => {
     if (connectionStatus === ConnectionStatus.CONNECTED) {
        try {
            await fetch(`${API_URL}/message`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ message: msg })
            });
        } catch (e) { console.error(e); }
    }
    setMessage(msg);
  };

  const handleSaveRecipients = async (list: Recipient[]) => {
      if (connectionStatus === ConnectionStatus.CONNECTED) {
        try {
            await fetch(`${API_URL}/recipients`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(list)
            });
        } catch (e) { console.error(e); }
    }
    setRecipients(list);
  };

  const renderContent = () => {
    switch (currentMode) {
      case AppMode.DASHBOARD:
        return <Dashboard 
            config={config} 
            isRunning={isRunning} 
            onToggleRun={handleToggleRun} 
            recentLogs={logs}
            totalRecipients={recipients.length}
        />;
      case AppMode.MESSAGES:
        return <MessageEditor 
            message={message} 
            setMessage={setMessage} 
            onSave={handleSaveMessage}
        />;
      case AppMode.RECIPIENTS:
        return <RecipientList 
            recipients={recipients} 
            setRecipients={setRecipients} 
            onSave={handleSaveRecipients}
        />;
      case AppMode.SETTINGS:
        return <ConfigForm 
            config={config} 
            setConfig={setConfig} 
            onSave={handleSaveConfig}
        />;
      case AppMode.LOGS:
        return <LogTerminal logs={logs} onClear={() => setLogs([])} />;
      default:
        return <Dashboard 
            config={config} 
            isRunning={isRunning} 
            onToggleRun={handleToggleRun} 
            recentLogs={logs}
            totalRecipients={recipients.length}
        />;
    }
  };

  return (
    <div className="flex min-h-screen bg-[#F3F4F6]">
      <Sidebar 
        currentMode={currentMode} 
        setMode={setMode} 
        connectionStatus={connectionStatus}
      />
      <div className="flex-1 ml-64">
        {renderContent()}
      </div>
    </div>
  );
};

export default App;
